	&lt;li&gt;&lt;span style=&quot;font-weight: bold;  &quot;&gt;It &lt;/span&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;marks&amp;nbsp;the first&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: bold;  &quot;&gt;day&lt;/span&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;&amp;nbsp;of the Stockholm Conference on the Human Environment&lt;/span&gt;&lt;/li&gt;
